cd "C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad" && PYTHONUTF8=1 python - <<'PY'
import csv
from collections import defaultdict
rows=[]
with open('lingxing_snapshot/asin_monthly.csv',encoding='utf-8-sig') as f:
    for r in csv.DictReader(f):
        rows.append(r)
model={'B0CR1R7FKP':'X2','B0CLLT85Y6':'X1','B0DHPN1DMJ':'S2','B0DCZQX11P':'S1','B0FNCQW2K3':'S3'}

# clean window net-weighted gross margin (2026-04, 2026-05)
def margin(months):
    agg=defaultdict(lambda:[0.0,0.0])  # net, gp
    for r in rows:
        if r['month'] in months and r['asin'] in model:
            n=float(r['net_amount']); gm=float(r['gross_margin'])
            agg[r['asin']][0]+=n; agg[r['asin']][1]+=n*gm
    return agg

for label,mos in [("clean 2026-04+05",{'2026-04','2026-05'}),("2026-05 only",{'2026-05'})]:
    agg=margin(mos)
    print(f"--- {label} ---  (net-weighted gross margin & margin$)")
    for a in sorted(model,key=lambda x:-(agg[a][1])):
        n,gp=agg[a]
        print(f"  {model[a]:3} net=${n:>11.0f}  margin={100*gp/n if n else 0:>5.1f}%  margin$=${gp:>10.0f}")

# S2 monthly gross_margin trend + return_rate (show ad-subsidised weak organic)
print("\n=== S2 (B0DHPN1DMJ) 逐月: cvr / gross_margin / return_rate ===")
for r in rows:
    if r['asin']=='B0DHPN1DMJ':
        print(f"  {r['month']}  cvr={float(r['cvr'])*100:>4.1f}%  gm={float(r['gross_margin'])*100:>6.1f}%  ret={float(r['return_rate'])*100:>5.1f}%  vol={r['volume']}")

# X2 monthly gross_margin volatility (single-point risk)
print("\n=== X2 (B0CR1R7FKP) 逐月 gross_margin (volatility) ===")
gms=[]
for r in rows:
    if r['asin']=='B0CR1R7FKP':
        gm=float(r['gross_margin']); gms.append(gm)
        print(f"  {r['month']}  gm={gm*100:>6.1f}%  vol={r['volume']}  net=${float(r['net_amount']):.0f}")

# S3 ramp both stores merged
print("\n=== S3 (B0FNCQW2K3) 品牌合并逐月 volume (7481+12137) ===")
s3=defaultdict(float)
for r in rows:
    if r['asin']=='B0FNCQW2K3':
        s3[r['month']]+=float(r['volume'])
for m in sorted(s3):
    print(f"  {m}  vol={s3[m]:.0f}")
PY

